import android.app.Activity\nimport android.content.Context\nimport android.content.Intent\nimport android.graphics.Bitmap\nimport android.graphics.Canvas\nimport android.media.projection.MediaProjection\nimport android.media.projection.MediaProjectionManager\nimport android.os.Build\nimport android.view.View\nimport androidx.annotation.RequiresApi\nimport java.io.File\nimport java.io.FileOutputStream\nimport java.io.IOException\n\nclass ScreenCaptureService(private val context: Context) {\n    private var mediaProjectionManager: MediaProjectionManager? = null\n    private var mediaProjection: MediaProjection? = null\n    private var captureIntent: Intent? = null\n\n    init {\n        mediaProjectionManager = context.getSystemService(Activity.MEDIA_PROJECTION_SERVICE) as MediaProjectionManager\n    }\n\n    @RequiresApi(Build.VERSION_CODES.LOLLIPOP)\n    fun startCapture(resultCode: Int, data: Intent) {\n        mediaProjection = mediaProjectionManager?.getMediaProjection(resultCode, data)\n    }\n\n    @RequiresApi(Build.VERSION_CODES.LOLLIPOP)\n    fun captureScreen(view: View, filePath: String) {\n        val bitmap = Bitmap.createBitmap(view.width, view.height, Bitmap.Config.ARGB_8888)\n        val canvas = Canvas(bitmap)\n        view.draw(canvas)\n        saveBitmap(bitmap, filePath)\n    }\n\n    private fun saveBitmap(bitmap: Bitmap, filePath: String) {\n        val file = File(filePath)\n        try {\n            val outputStream = FileOutputStream(file)\n            bitmap.compress(Bitmap.CompressFormat.PNG, 100, outputStream)\n            outputStream.flush()\n            outputStream.close()\n        } catch (e: IOException) {\n            e.printStackTrace()\n        }\n    }\n}